USE robodynamics_db;
START TRANSACTION;

-- Archival metadata for research tracking

SET @archive_batch = '20260228_career_discovery_refresh';
UPDATE rd_ci_question_bank
   SET status='ARCHIVED',
       archived_at=NOW(),
       archive_reason='Replaced by career_discovery CSV clean set',
       archive_batch=@archive_batch
 WHERE module_code='APTIPATH' AND assessment_version='v3' AND status='ACTIVE';

-- Fresh AptiPath v3 active set from question_bank_career_discovery.csv

-- Refresh legacy VidaPath tables from the same CSVs
DELETE FROM vida_path_question_bank;
DELETE FROM vida_path_future_career;

COMMIT;

SELECT 'ACTIVE_V3_COUNT' AS metric, COUNT(*) AS val FROM rd_ci_question_bank WHERE module_code='APTIPATH' AND assessment_version='v3' AND status='ACTIVE';
SELECT 'ACTIVE_V3_DISTINCT_TEXT' AS metric, COUNT(DISTINCT question_text) AS val FROM rd_ci_question_bank WHERE module_code='APTIPATH' AND assessment_version='v3' AND status='ACTIVE';
SELECT section_code, COUNT(*) AS cnt FROM rd_ci_question_bank WHERE module_code='APTIPATH' AND assessment_version='v3' AND status='ACTIVE' GROUP BY section_code ORDER BY cnt DESC;
SELECT 'ACTIVE_V3_DUP_TEXT_GROUPS' AS metric, COUNT(*) AS val FROM (SELECT question_text FROM rd_ci_question_bank WHERE module_code='APTIPATH' AND assessment_version='v3' AND status='ACTIVE' GROUP BY question_text HAVING COUNT(*)>1) t;
SELECT 'ARCHIVED_V3_COUNT' AS metric, COUNT(*) AS val FROM rd_ci_question_bank WHERE module_code='APTIPATH' AND assessment_version='v3' AND status='ARCHIVED';
SELECT 'VIDA_Q_COUNT' AS metric, COUNT(*) AS val FROM vida_path_question_bank;
SELECT 'VIDA_CAREER_COUNT' AS metric, COUNT(*) AS val FROM vida_path_future_career;

